int main()
{
    unsigned int n{};
    std::cin >> n;

    std::cout << "dec: " << std::dec << n << "\n";
    std::cout << "hex: " << std::hex << n << "\n";
    std::cout << "oct: " << std::oct << n << "\n";

    return 0;
}

