solution_code:
#include <iostream>

unsigned int extract_nibble(unsigned int value)
{
    const unsigned int NIBBLE_MASK{ 0x0Fu };
    return value & NIBBLE_MASK;
}

int main()
{
    unsigned int n{};
    std::cin >> n;
    std::cout << extract_nibble(n) << "\n";
    return 0;
}
